mapper.select:
SELECT BOOK_ID AS bookId, TITLE AS title, AUTHOR AS author,
       PUBLISHER AS publisher, STATUS AS status, CATEGORY AS category
FROM BOOK WHERE BOOK_ID = #{bookId}

mapper.update:
UPDATE BOOK SET TITLE=#{title}, AUTHOR=#{author},
       PUBLISHER=#{publisher}, STATUS=#{status}, CATEGORY=#{category}
WHERE BOOK_ID=#{bookId}

mapper.select:
SELECT BOOK_ID AS bookId, TITLE AS title, AUTHOR AS author, PUBLISHER AS publisher, STATUS AS status, CATEGORY AS category FROM BOOK
AND TITLE LIKE CONCAT('%',#{keyword},'%') AND AUTHOR LIKE CONCAT('%',#{keyword},'%') AND PUBLISHER LIKE CONCAT('%',#{keyword},'%') AND CATEGORY = #{keyword}
ORDER BY TITLE ASC

SELECT COUNT(*) FROM BOOK
AND TITLE LIKE CONCAT('%',#{keyword},'%') AND AUTHOR LIKE CONCAT('%',#{keyword},'%') AND PUBLISHER LIKE CONCAT('%',#{keyword},'%')
AND CATEGORY = #{category} AND TITLE LIKE CONCAT(#{initial},'%') AND STATUS = #{statusFilter}
